## **更灵活的 Python 版本**

创建 `test_video_model.py`:

```python
#!/usr/bin/env python3
import requests
import base64
import json
import sys
import os

# 配置
BASE_URL = "http://10.102.200.26:8000"
MODEL = "/mnt/shared-storage-user/puyudelivery/user/puyudilivery/ckpts/xtuner_saved_model/interns1_1_sft/interns1_1_base02_20260111a_lr3e5_512gpu_fp8/20260111154122/hf-946-fp8"

def encode_video_base64(video_path):
    """将视频文件编码为base64"""
    with open(video_path, "rb") as video_file:
        return base64.b64encode(video_file.read()).decode('utf-8')

def test_video_with_base64(video_path, prompt="请详细描述这个视频的内容"):
    """使用Base64编码的视频测试"""
    print(f"正在编码视频: {video_path}")
    video_b64 = encode_video_base64(video_path)

    # 获取视频文件扩展名
    ext = os.path.splitext(video_path)[1].lower()
    mime_type_map = {
        '.mp4': 'video/mp4',
        '.avi': 'video/x-msvideo',
        '.mov': 'video/quicktime',
        '.webm': 'video/webm'
    }
    mime_type = mime_type_map.get(ext, 'video/mp4')

    payload = {
        "model": MODEL,
        "messages": [
            {
                "role": "user",
                "content": [
                    {
                        "type": "text",
                        "text": prompt
                    },
                    {
                        "type": "video_url",
                        "video_url": {
                            "url": f"data:{mime_type};base64,{video_b64}"
                        }
                    }
                ]
            }
        ],
        "temperature": 0.7,
        "max_tokens": 1000
    }

    return send_request(payload)

def test_video_with_url(video_url, prompt="请详细描述这个视频的内容"):
    """使用视频URL测试"""
    payload = {
        "model": MODEL,
        "messages": [
            {
                "role": "user",
                "content": [
                    {
                        "type": "text",
                        "text": prompt
                    },
                    {
                        "type": "video_url",
                        "video_url": {
                            "url": video_url
                        }
                    }
                ]
            }
        ],
        "temperature": 0.7,
        "max_tokens": 1000
    }

    return send_request(payload)

def test_text_only(prompt="你好，请介绍一下自己的多模态能力"):
    """纯文本测试"""
    payload = {
        "model": MODEL,
        "messages": [
            {
                "role": "user",
                "content": prompt
            }
        ],
        "temperature": 0.7,
        "max_tokens": 500
    }

    return send_request(payload)

def send_request(payload):
    """发送请求到API"""
    url = f"{BASE_URL}/v1/chat/completions"
    headers = {"Content-Type": "application/json"}

    try:
        response = requests.post(url, headers=headers, json=payload, timeout=120)
        response.raise_for_status()
        return response.json()
    except requests.exceptions.RequestException as e:
        return {"error": str(e)}

def print_response(response):
    """美化打印响应"""
    if "error" in response:
        print(f"❌ 错误: {response['error']}")
        return

    if "choices" in response and len(response["choices"]) > 0:
        content = response["choices"][0]["message"]["content"]
        print(f"✅ 模型回复:\n{content}")
        print(f"\n📊 Token使用: {response.get('usage', {})}")
    else:
        print(f"⚠️  未预期的响应格式:\n{json.dumps(response, indent=2, ensure_ascii=False)}")

# 主程序
if __name__ == "__main__":
    print("=" * 60)
    print("多模态模型测试脚本")
    print("=" * 60)

    # 测试1: 本地视频文件（Base64）
    video_path = "/mnt/shared-storage-gpfs2/sfteval/wuyue/test_video/clip_3_removed.mp4"
    if os.path.exists(video_path):
        print("\n📹 测试1: 使用本地视频文件（Base64编码）")
        print("-" * 60)
        response = test_video_with_base64(video_path, "请详细描述视频中发生了什么")
        print_response(response)
    else:
        print(f"\n⚠️  视频文件不存在: {video_path}")

    # 测试2: 视频URL（需要替换为实际的URL）
    print("\n\n🌐 测试2: 使用视频URL")
    print("-" * 60)
    # video_url = "https://example.com/sample.mp4"  # 替换为实际URL
    # response = test_video_with_url(video_url, "描述这个视频")
    # print_response(response)
    print("⏭️  跳过（请设置实际的视频URL）")

    # 测试3: 纯文本
    print("\n\n💬 测试3: 纯文本对话")
    print("-" * 60)
    response = test_text_only("你支持哪些类型的多模态输入？")
    print_response(response)

    print("\n" + "=" * 60)
    print("测试完成")
    print("=" * 60)
